-- ============================================================
-- fullstack-developer-roadmap.seed.sql
-- Full Stack Developer roadmap seed.
-- Frontend-first curated full stack path with backend, database, auth, testing,
-- deployment, performance, and capstone coverage.
-- Re-runnable/idempotent for this roadmap title.
-- ============================================================

BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- Clean previous copy of this specific roadmap only.
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed')
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed')
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed')
);

DELETE FROM public.roadmap
WHERE title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed');

INSERT INTO public.career_role (name, slug, description, category, is_active)
VALUES (
    'Full Stack Developer',
    'full-stack-developer',
    'Frontend-first full stack development path covering client-side engineering, APIs, databases, authentication, testing, deployment, performance, and production-ready project work.',
    'Software Engineering',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'full-stack-developer'
), inserted_roadmap AS (
    INSERT INTO public.roadmap (career_role_id, title, description, roadmap_type, source_type, visibility)
    SELECT
        career_role_id,
        'Full Stack Developer Roadmap',
        'A structured learning path for becoming a full stack developer with a frontend-first focus, covering web fundamentals, HTML, CSS, JavaScript, TypeScript, React, frontend architecture, backend APIs, databases, authentication, testing, deployment, performance, DevOps awareness, and portfolio-ready full stack applications.',
        'template',
        'static',
        'public'
    FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    INSERT INTO public.roadmap_version
    (roadmap_id, version_number, status, title, description, estimated_total_hours, generation_status, generation_context, layout_direction, layout_algorithm, published_at)
    SELECT
        roadmap_id,
        1,
        'published',
        'Full Stack Developer Roadmap v1',
        'A practical frontend-first full stack roadmap that moves from web fundamentals to production-ready applications through guided topics, checkpoints, optional practice projects, and required milestone projects.',
        410,
        'none',
        '{"source":"platform-generated","referenceSeeds":["frontend-developer","backend-developer"],"focus":"frontend-first full stack","estimatedHoursPolicy":"representative required path"}'::jsonb,
        'TB',
        'custom',
        now()
    FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

